module PIPO_Registers (
    input wire [7:0] data_in,
    input wire clk,
    input wire reset,
    input wire load,
    output reg [7:0] data_out
);
  wire [7:0] _tap_data_in = data_in & {8{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out <= 8'b00000000;
        end else if (load) begin
            data_out <= data_in;
        end
    end
endmodule
